SELECT id, val,
  SUM(val) OVER (ORDER BY id) AS running_total
FROM (VALUES (1, 10), (2, 20), (3, 30)) AS t(id, val);

SELECT
  EXTRACT(YEAR FROM DATE '2024-03-15') AS yr,
  EXTRACT(MONTH FROM DATE '2024-03-15') AS mo;

SELECT name, score,
  ROW_NUMBER() OVER (ORDER BY score DESC) AS rank
FROM (VALUES ('Alice', 85), ('Bob', 92), ('Carol', 78)) AS t(name, score);

WITH RECURSIVE nums AS (
  SELECT 1 AS n
  UNION ALL
  SELECT n + 1 FROM nums WHERE n < 5
)
SELECT SUM(n) FROM nums;

